import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'
import {Tab, Tabs, TabList, TabPanel} from 'react-tabs'
import 'react-tabs/style/react-tabs.css'
import FullCalendar from '@fullcalendar/react' // must go before plugins
import interactionPlugin from "@fullcalendar/interaction" // needed for dayClick
import timeGridPlugin from '@fullcalendar/timegrid'


class Room extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            screen: 0, selectedDate: "", availableRooms: [], showRoom: false, selectedRoom: {}, showTime: false, events: [], showConfirm: false, selectedStart: "", selectedEnd: "",
            availableSelectedDate: "", availableSelectedStart: "", availableSelectedEnd: "", showAvailableSelect: false, availableEvents: [],
            bookedSpaceEvents: [], loadingRoom: false
        };

        this.officeHourStart = "06:00 AM"
        this.officeHourStart2 = "06:30 AM"
        this.officeHourEnd = "06:00 PM"

        this.slotMinTime="06:00:00"
        this.slotMaxTime="18:00:00"

    }

    handleCancelSetAvailable = () => {
        this.setState({showAvailableSelect: false})
    }


    handleCancelBooking = () => {
        this.setState({showConfirm: false})
    }

    handleBooking = () => {

        var events = this.state.events

        //console.log(this.state.selectedRoom)
        var startTime = Moment(this.state.selectedDate).format("YYYY-MM-DD") + "T" + Moment(this.state.selectedStart).format("HH:mm:ss")
        var endTime = Moment(this.state.selectedDate).format("YYYY-MM-DD") + "T" + Moment(this.state.selectedEnd).format("HH:mm:ss")
        var message = document.getElementById("comment").value


        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        var addScheduleRequest = {id: this.state.selectedRoom.id, start_date_time: startTime, end_date_time: endTime, comment: message}


        var backUrl = properties.backend + `addschedule`

        fetch(backUrl, {
          "method": "POST",
          headers: headers,
          body: JSON.stringify(addScheduleRequest)

        })
        .then(response => response.json())
        .then(response => {



            events.push({id: response.id, title: response.cyber_user.split("::")[1], start: startTime, end: endTime})

            this.setState({events: events})
            this.setState({showConfirm: false})

        })
        .catch(err => {
          console.log(err);
        });




    }

    handleSetAvailable = () => {
        var availableEvents = this.state.availableEvents


        var startTime = Moment(this.state.availableSelectedDate).format("YYYY-MM-DD") + "T" + Moment(this.state.availableSelectedStart).format("HH:mm:ss")
        var endTime = Moment(this.state.availableSelectedDate).format("YYYY-MM-DD") + "T" + Moment(this.state.availableSelectedEnd).format("HH:mm:ss")

        var messageAvailable = document.getElementById("commentAvailable").value


        availableEvents.push({title: "P.O. 5528", start: startTime, end: endTime})

        //console.log(events)

        this.setState({availableEvents: availableEvents})
        this.setState({showAvailableSelect: false})



    }



    handleAvailableSelect = (selectionInfo) => {
        //console.log(selectionInfo)


        var availableEventsFilter = this.state.availableEvents.filter(Record => Moment(Record.start).format("YYYY-MM-DD") === Moment(selectionInfo.start).format("YYYY-MM-DD"))


        var foundOverlap = false

        var startTime = Moment(Moment(selectionInfo.start).format("YYYY-MM-DD") + "T" + Moment(selectionInfo.start).format("HH:mm:ss"))
        var endTime = Moment(Moment(selectionInfo.end).format("YYYY-MM-DD") + "T" + Moment(selectionInfo.end).format("HH:mm:ss"))


        var availableSelectedDate = Moment(selectionInfo.start).format("YYYY-MM-DD")
        //this.setState({availableSelectedDate: availableSelectedDate})

        for(var index in availableEventsFilter) {
            var eventStartTime = Moment(availableEventsFilter[index].start)
            var eventEndTime = Moment(availableEventsFilter[index].end)
            if (startTime >= eventStartTime && startTime < eventEndTime) {
                foundOverlap = true
            }
            if (endTime > eventStartTime && endTime <= eventEndTime) {
                foundOverlap = true
            }
            if (eventStartTime >= startTime && eventStartTime < endTime) {
                foundOverlap = true
            }
            if (eventEndTime > startTime && eventEndTime <= endTime) {
                foundOverlap = true
            }
        }


        if (!foundOverlap) {
            this.setState({showAvailableSelect: true})
            this.setState({availableSelectedStart: startTime})
            this.setState({availableSelectedEnd: endTime})
            this.setState({availableSelectedDate: availableSelectedDate})
        } else {
            alert("The selected time has been setted")
            this.setState({showAvailableSelect: false})
        }



    }


    handleCancelReservation = (id) => {

        console.log(id)
        var bookedSpaceEvents = this.state.bookedSpaceEvents.filter(Record => Record.id != id)

        this.setState({bookedSpaceEvents: bookedSpaceEvents})

    }


    handleSelect = (selectionInfo) => {
        console.log(selectionInfo)



        var eventsFilter = this.state.events.filter(Record => Moment(Record.start).format("YYYY-MM-DD") === Moment(this.state.selectedDate).format("YYYY-MM-DD"))

        //console.log(eventsFilter)

        var foundOverlap = false

        var startTime = Moment(Moment(this.state.selectedDate).format("YYYY-MM-DD") + "T" + Moment(String(selectionInfo.start)).format("HH:mm:ss"))
        var endTime = Moment(Moment(this.state.selectedDate).format("YYYY-MM-DD") + "T" + Moment(String(selectionInfo.end)).format("HH:mm:ss"))


        for(var index in eventsFilter) {
            var eventStartTime = Moment(eventsFilter[index].start)
            var eventEndTime = Moment(eventsFilter[index].end)
            if (startTime >= eventStartTime && startTime < eventEndTime) {
                foundOverlap = true
            }
            if (endTime > eventStartTime && endTime <= eventEndTime) {
                foundOverlap = true
            }
            if (eventStartTime >= startTime && eventStartTime < endTime) {
                foundOverlap = true
            }
            if (eventEndTime > startTime && eventEndTime <= endTime) {
                foundOverlap = true
            }
        }


        if (!foundOverlap) {


            this.setState({showConfirm: true})
            this.setState({selectedStart: String(selectionInfo.start)})
            this.setState({selectedEnd: String(selectionInfo.end)})


        } else {
            alert("The selected time has been occupied")
            this.setState({showConfirm: false})
        }


    }


    handleCheckTime = () => {
        if (JSON.stringify(this.state.selectedRoom).length > 2) {
            this.setState({showRoom: false})
            this.setState({showTime: true})
            this.setState({showConfirm: false})

            var roomInfo = this.state.availableRooms.filter(Record => Record.id === this.state.selectedRoom.id)[0]
            var scheduled = roomInfo.scheduled.filter(Record2 => Moment(Record2.start_date_time).format("MM/DD/YYYY") === this.state.selectedDate)

            var events = []

            scheduled.map(eventRec => {
                events.push({id: eventRec.id, title: eventRec.cyber_user.split("::")[1], start: eventRec.start_date_time, end: eventRec.end_date_time})
            })

            /*
            var events =  [
                {
                    id: 2,
                    title: this.state.selectedRoom.label + ": Keith Siu",
                    start: '2021-12-15T13:00:00',
                    end: '2021-12-15T15:00:00'
                }
            ]
            */



            this.setState({events: events})



        } else {
            alert("please select room(s)")
        }
    }

    handleRoomSelect = (selectedOptions) => {
        //console.log(selectedOptions)
        this.setState({selectedRoom: selectedOptions})
    }



    handleDateChange = (date) => {

        this.setState({loadingRoom: true})

        this.setState({selectedDate: new DateObject(date).format()})

        this.setState({showConfirm: false})
        this.setState({showRoom: false})
        this.setState({showTime: false})

        /*
        if (this.state.selectedDate !== date) {
          this.setState({selectedDate: date})
          //console.log(date);var myDate = new Date(date);console.log(myDate);
        }
        */
        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `getavailableroom`, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            //response

            var rooms = []
            // 6 am to 5:30 pm
            // 6 am - 6:30 am
            // 6:30 am - 7:00 am 

            //var hourRange = moment(date)

            var selectedDate = new DateObject(date).format()
            //console.log(selectedDate)

            //var hourRangeEnd = Moment(selectedDate + " " + this.officeHourEnd, "MM/DD/YYYY HH:mm a")
            //console.log(hourRangeStart.format("HH:mm:ss"))
            //console.log(hourRangeEnd.format("HH:mm:ss"))

            //console.log(response)
            response.map(Record => {
                var scheduledfilter = Record.scheduled.filter(Record => Moment(Record.start_date_time).format("MM/DD/YYYY") === selectedDate)
                var exitWhileLoop = false
                var addToChoice = false

                if (Record.owner === null || Record.owner.length === 0) { 
                    var hourRangeStart = Moment(selectedDate + " " + this.officeHourStart, "MM/DD/YYYY HH:mm a")
                    var hourRangeStart2 = Moment(selectedDate + " " + this.officeHourStart2, "MM/DD/YYYY HH:mm a")
                    var hourRangeEnd = Moment(selectedDate + " " + this.officeHourEnd, "MM/DD/YYYY HH:mm a")

                    while (hourRangeStart < hourRangeEnd && !exitWhileLoop) {
                    //console.log(hourRangeStart.format("HH:mm:ss"))

                        var foundOverlap = false
                        scheduledfilter.map(record2 => {
                            var startTime = Moment(record2.start_date_time)
                            var endTime = Moment(record2.end_date_time)
                            if (hourRangeStart >= startTime && hourRangeStart < endTime) {
                                foundOverlap = true
                            }
                            if (hourRangeStart2 > startTime && hourRangeStart2 <= endTime) {
                                foundOverlap = true
                            }
                            if (startTime >= hourRangeStart && startTime < hourRangeStart2) {
                                foundOverlap = true
                            }
                            if (endTime > hourRangeStart && endTime <= hourRangeStart2) {
                                foundOverlap = true
                            }
                        })

                        if (!foundOverlap) {
                            exitWhileLoop = true
                            addToChoice = true
                        }

                        hourRangeStart.add(30, "minutes")
                        hourRangeStart2.add(30, "minutes")
                    }
                } else {

                    var availablefilter = Record.available_date_json.filter(Rec2 => Moment(Rec2.startDate).format("MM/DD/YYYY") === selectedDate)

                    availablefilter.map(availRec => {

                        var hourRangeStart = Moment(availRec.startDate + " " + availRec.startTime, "MM/DD/YYYY HH:mm a")
                        var hourRangeStart2 = Moment(availRec.endDate + " " + availRec.startTime, "MM/DD/YYYY HH:mm a").add(30, "minutes")
                        var hourRangeEnd = Moment(selectedDate + " " + availRec.endTime, "MM/DD/YYYY HH:mm a")

                        var exitWhileLoop = false

                        while (hourRangeStart < hourRangeEnd && !exitWhileLoop) {

                                var foundOverlap = false
                                scheduledfilter.map(record2 => {
                                    var startTime = Moment(record2.start_date_time)
                                    var endTime = Moment(record2.end_date_time)
                                    if (hourRangeStart >= startTime && hourRangeStart < endTime) {
                                        foundOverlap = true
                                    }
                                    if (hourRangeStart2 > startTime && hourRangeStart2 <= endTime) {
                                        foundOverlap = true
                                    }
                                    if (startTime >= hourRangeStart && startTime < hourRangeStart2) {
                                        foundOverlap = true
                                    }
                                    if (endTime > hourRangeStart && endTime <= hourRangeStart2) {
                                        foundOverlap = true
                                    }
                                })

                                if (!foundOverlap) {
                                    exitWhileLoop = true
                                    addToChoice = true
                                }

                                hourRangeStart.add(30, "minutes")
                                hourRangeStart2.add(30, "minutes")
                        }
                    })

                }





                if (addToChoice) {
                    var roomInfo = Record
                    roomInfo.value = Record.id
                    roomInfo.label = Record.room_name 
                    rooms.push(roomInfo)
                }
